INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (1, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。", 1, 1, 1011);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。", 1, 2, 1021);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2, "育成ミッションは、特定の条件を達成することで報酬が獲得できる\n期間限定のミッションでございます。ステップごとに設定された\nミッションを全て達成すると、次のステップに進めますよ。", 1, 3, 1031);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (4, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 1, 4, 1041);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (5, "ボスバトルには３種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。", 1, 5, 1051);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (1, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。", 2, 1, 2011);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。", 2, 2, 2021);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (4, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 2, 4, 2041);
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (5, "ボスバトルには２種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。", 2, 5, 2051);
